'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { logoutAction } from '@/app/actions/auth'

const NAV_ITEMS = [
  { href: '/dashboard', label: 'Dashboard', icon: HomeIcon },
  { href: '/sermons', label: 'Sermons', icon: VideoIcon },
  { href: '/garden', label: 'Garden', icon: GardenIcon },
  { href: '/documents', label: 'Documents', icon: DocumentIcon },
]

const ADMIN_NAV_ITEMS = [
  { href: '/admin', label: 'Admin', icon: AdminIcon },
]

interface SidebarProps {
  userName: string
  churchName: string
  role: string
}

export function Sidebar({ userName, churchName, role }: SidebarProps) {
  const pathname = usePathname()

  return (
    <aside className="flex flex-col w-60 min-h-screen bg-stone-900 text-stone-100">
      {/* Logo */}
      <div className="px-6 py-5 border-b border-stone-800">
        <span className="text-xl font-bold tracking-tight">Chosen</span>
        <p className="text-xs text-stone-400 mt-0.5 truncate">{churchName}</p>
      </div>

      {/* Nav */}
      <nav className="flex-1 px-3 py-4 space-y-0.5">
        {NAV_ITEMS.map(({ href, label, icon: Icon }) => {
          const active = pathname === href || pathname.startsWith(href + '/')
          return (
            <Link
              key={href}
              href={href}
              className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                active
                  ? 'bg-emerald-700 text-white'
                  : 'text-stone-300 hover:bg-stone-800 hover:text-white'
              }`}
            >
              <Icon className="w-4 h-4 shrink-0" />
              {label}
            </Link>
          )
        })}

        {role === 'admin' && (
          <>
            <div className="pt-4 pb-1 px-3">
              <p className="text-xs font-semibold uppercase tracking-wider text-stone-500">
                Super Admin
              </p>
            </div>
            {ADMIN_NAV_ITEMS.map(({ href, label, icon: Icon }) => {
              const active = pathname === href || pathname.startsWith(href + '/')
              return (
                <Link
                  key={href}
                  href={href}
                  className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                    active
                      ? 'bg-emerald-700 text-white'
                      : 'text-stone-300 hover:bg-stone-800 hover:text-white'
                  }`}
                >
                  <Icon className="w-4 h-4 shrink-0" />
                  {label}
                </Link>
              )
            })}
          </>
        )}
      </nav>

      {/* User + Logout */}
      <div className="px-3 py-4 border-t border-stone-800">
        <div className="px-3 py-2 mb-1">
          <p className="text-sm font-medium text-stone-200 truncate">{userName}</p>
          <p className="text-xs text-stone-400 capitalize">{role.replace('_', ' ')}</p>
        </div>
        <form action={logoutAction}>
          <button
            type="submit"
            className="w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium text-stone-400 hover:bg-stone-800 hover:text-white transition-colors"
          >
            <LogoutIcon className="w-4 h-4 shrink-0" />
            Sign out
          </button>
        </form>
      </div>
    </aside>
  )
}

